Here's an updated `BaseRepository` class in C# that allows you to find by a dynamic field. This example uses Entity Framework Core as the ORM.

```csharp
public abstract class BaseRepository<TEntity> : IBaseRepository<TEntity> where TEntity : class
{
    protected readonly DbContext _dbContext;
    protected readonly DbSet<TEntity> _dbSet;

    public BaseRepository(DbContext dbContext)
    {
        _dbContext = dbContext;
        _dbSet = dbContext.Set<TEntity>();
    }

    public virtual async Task<TEntity> FindByIdAsync(int id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<TEntity> FindByDynamicAsync(string fieldName, object value)
    {
        return await _dbSet
            .Where(x => x.GetType().GetProperty(fieldName).GetValue(x, null).Equals(value))
            .FirstOrDefaultAsync();
    }

    // Other methods...
}
```

